// Valida HMAC X-Conferente-Signature e campos obrigatórios

const crypto = require('crypto');

const body = $input.first().json.body;
const headers = $input.first().json.headers;

// --- Validação HMAC ---
const conferenteSecret = $env.CONFERENTE_SECRET;
if (!conferenteSecret) {
  throw new Error('GP_CONFIG_ERROR: CONFERENTE_SECRET não configurado');
}

const signatureHeader = headers['x-conferente-signature'] || headers['X-Conferente-Signature'] || '';
if (!signatureHeader) {
  throw new Error('GP_AUTH_FAILED: Header X-Conferente-Signature ausente');
}

const receivedHex = signatureHeader.replace('sha256=', '');
const rawBody = JSON.stringify(body);
const expectedHex = crypto
  .createHmac('sha256', conferenteSecret)
  .update(rawBody)
  .digest('hex');

let signatureValid = false;
try {
  signatureValid = crypto.timingSafeEqual(
    Buffer.from(receivedHex, 'hex'),
    Buffer.from(expectedHex, 'hex')
  );
} catch (e) {
  throw new Error(`GP_AUTH_FAILED: Erro na comparação HMAC: ${e.message}`);
}

if (!signatureValid) {
  throw new Error('GP_AUTH_FAILED: Assinatura HMAC X-Conferente-Signature inválida');
}

// --- Validação do payload ---
const {
  ingestion_id, project_id, normalized_text, extraction_metadata,
  provider_chain, callback_url, doc_classification, active_personas,
  shared_context
} = body;

if (!ingestion_id || !/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(ingestion_id)) {
  throw new Error('GP_INVALID: ingestion_id deve ser UUID v4');
}

if (!project_id) {
  throw new Error('GP_INVALID: project_id ausente');
}

if (!normalized_text || typeof normalized_text !== 'string' || normalized_text.trim().length === 0) {
  throw new Error('GP_INVALID: normalized_text vazio ou ausente');
}

if (!provider_chain || !Array.isArray(provider_chain) || provider_chain.length === 0) {
  throw new Error('GP_INVALID: provider_chain ausente ou vazia');
}

if (!doc_classification) {
  throw new Error('GP_INVALID: doc_classification ausente');
}

if (!active_personas || !Array.isArray(active_personas)) {
  throw new Error('GP_INVALID: active_personas ausente');
}

return [{
  json: {
    ingestion_id,
    project_id,
    normalized_text,
    extraction_metadata: extraction_metadata || {},
    provider_chain,
    callback_url: callback_url || `${$env.GCA_CALLBACK_BASE_URL}/api/webhooks/ingestion-complete`,
    doc_classification,
    active_personas,
    shared_context: shared_context || {},
    started_at: new Date().toISOString()
  }
}];

// Extrai JSON da resposta LLM e formata como PersonaOutput v2
// Schema canônico: PersonaOutput.schema.json

const llmResponse = $input.first().json;
const upstream = $('Montar prompt GP').first().json;

const startedAt = upstream.started_at;
const completedAt = new Date().toISOString();
const modelUsed = upstream.provider_chain[0]?.model || 'unknown';

let rawText = '';

// Anthropic: content[]
if (llmResponse.content && Array.isArray(llmResponse.content)) {
  rawText = llmResponse.content.map(c => c.text || '').join('');
} else if (llmResponse.choices && Array.isArray(llmResponse.choices)) {
  // OpenAI-compat (DeepSeek)
  rawText = llmResponse.choices[0]?.message?.content || '';
} else {
  throw new Error('GP_PARSE_FAILED: Estrutura de resposta LLM desconhecida');
}

// Remove possíveis blocos markdown
rawText = rawText.trim();
if (rawText.startsWith('```')) {
  rawText = rawText.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
}

let llmData;
try {
  llmData = JSON.parse(rawText);
} catch (e) {
  // Fallback: output com status failed para não travar o Consolidador
  llmData = {
    scores: { escopo: 50, stack: 50, dados: 50, implementacao: 50, testes: 50 },
    approved: false,
    issues: [{
      chunk_id: '',
      category: 'missing',
      severity: 'blocker',
      description: `GP: falha ao parsear resposta LLM — ${e.message}`,
      suggested_action: 'Revisar documento manualmente'
    }],
    questions: [],
    justification: '(Análise de GP indisponível — parse error)',
    metadata: { tentative: true }
  };
}

// Tokens consumidos
let inputTokens = 0;
let outputTokens = 0;
if (llmResponse.usage) {
  inputTokens = llmResponse.usage.input_tokens || llmResponse.usage.prompt_tokens || 0;
  outputTokens = llmResponse.usage.output_tokens || llmResponse.usage.completion_tokens || 0;
}

// Score agregado (média dos 5 sub-scores)
const scores = llmData.scores || {};
const scoreValues = [
  scores.escopo || 0,
  scores.stack || 0,
  scores.dados || 0,
  scores.implementacao || 0,
  scores.testes || 0
];
const aggregatedScore = Math.round(scoreValues.reduce((a, b) => a + b, 0) / scoreValues.length);

// Mapeia issues para findings canônicos do PersonaOutput
const findings = (llmData.issues || []).map((issue, idx) => ({
  id: `gp-finding-${idx + 1}`,
  severity: issue.severity === 'blocker' ? 'critical' : issue.severity === 'warning' ? 'medium' : 'info',
  category: issue.category || 'general',
  title: issue.description ? issue.description.substring(0, 120) : `Issue GP-${idx + 1}`,
  description: issue.description || '',
  location_hint: issue.chunk_id || null,
  evidence_excerpt: null
}));

// Mapeia questions como recomendações (precisam de input humano)
const recommendations = (llmData.questions || []).map((q, idx) => ({
  id: `gp-rec-${idx + 1}`,
  priority: q.severity === 'blocker' ? 'urgent' : q.severity === 'important' ? 'high' : 'medium',
  action: q.question_text || '',
  expected_impact: q.rationale || '',
  estimated_effort: 'small',
  linked_finding_ids: []
}));

// OCG contributions — persona GP
const ocgIndividual = {
  schedule_assessment: {
    declared_schedule: null,
    feasibility: llmData.approved ? 'feasible' : 'undefined',
    rationale: llmData.justification || ''
  },
  critical_path_identified: [],
  risk_register_local: (llmData.issues || [])
    .filter(i => i.category === 'risco' || i.severity === 'blocker')
    .map(i => ({
      risk: i.description,
      category: 'scope',
      probability: i.severity === 'blocker' ? 'high' : 'medium',
      impact: i.severity === 'blocker' ? 'high' : 'medium',
      mitigation: i.suggested_action || null
    })),
  governance_structure: {
    raci_defined: false,
    decision_forum: null,
    communication_cadence: null,
    escalation_path: null
  },
  methodology_fit: {
    declared_method: null,
    fit_to_project: 'questionable',
    rationale: '(inferido automaticamente)'
  },
  gp_approved: llmData.approved,
  gp_scores: llmData.scores,
  questions_pending: (llmData.questions || []).length
};

const ocgGlobalDelta = {
  project_milestones: [],
  project_dependencies_master: [],
  project_risks_register: (llmData.issues || [])
    .filter(i => i.severity === 'blocker')
    .map(i => ({
      risk: i.description,
      category: i.category || 'scope',
      status: 'open'
    })),
  governance_artifacts: [],
  effort_signals: []
};

// Monta PersonaOutput v2 canônico
const personaOutput = {
  schema_version: 'PersonaOutput-v2',
  ingestion_id: upstream.ingestion_id,
  persona_tag: 'GP',
  persona_name: 'Gerente de Projetos',
  execution_metadata: {
    started_at: startedAt,
    completed_at: completedAt,
    model_used: modelUsed,
    tokens_consumed: {
      input: inputTokens,
      output: outputTokens
    },
    chunk_index: 0,
    total_chunks: 1,
    extraction_source_format: upstream.extraction_metadata?.source_format || 'txt'
  },
  score: aggregatedScore,
  score_rationale: (llmData.justification || '').substring(0, 280),
  blocking: false,
  blocking_reason: null,
  status: 'completed',
  findings,
  recommendations,
  ocg_contributions: {
    individual: ocgIndividual,
    global_delta: ocgGlobalDelta
  }
};

return [{
  json: {
    persona_output: personaOutput,
    provider_chain: upstream.provider_chain,
    callback_url: upstream.callback_url,
    ingestion_id: upstream.ingestion_id,
    project_id: upstream.project_id
  }
}];

// G3 — Auto-validação do PersonaOutput antes do callback ao Consolidador
// Valida campos obrigatórios conforme PersonaOutput.schema.json

const item = $input.first().json;
const output = item.persona_output;

const validationReport = {
  schema_version_check: false,
  score_in_range: false,
  evidence_excerpts_present: false,
  ocg_individual_non_empty: false,
  ocg_global_delta_non_empty: false
};

const errors = [];

// schema_version
if (output.schema_version === 'PersonaOutput-v2') {
  validationReport.schema_version_check = true;
} else {
  errors.push('G3: schema_version deve ser PersonaOutput-v2');
}

// persona_tag
const TAGS_CANONICAS = ['AUD', 'GP', 'ARQ', 'DBA', 'DEV', 'QA', 'UX', 'UI', 'SEG', 'CONF', 'LGPD', 'NEG'];
if (!TAGS_CANONICAS.includes(output.persona_tag)) {
  errors.push(`G3: persona_tag '${output.persona_tag}' não é canônica`);
}
if (output.persona_tag !== 'GP') {
  errors.push('G3: persona_tag deve ser GP neste workflow');
}

// ingestion_id UUID v4
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(output.ingestion_id)) {
  errors.push('G3: ingestion_id deve ser UUID v4');
}

// score 0-100
if (typeof output.score === 'number' && output.score >= 0 && output.score <= 100) {
  validationReport.score_in_range = true;
} else {
  errors.push(`G3: score fora do intervalo 0-100 (valor: ${output.score})`);
}

// execution_metadata obrigatório
if (!output.execution_metadata?.started_at || !output.execution_metadata?.completed_at) {
  errors.push('G3: execution_metadata.started_at e completed_at obrigatórios');
}
if (!output.execution_metadata?.model_used) {
  errors.push('G3: execution_metadata.model_used obrigatório');
}
if (typeof output.execution_metadata?.tokens_consumed?.input !== 'number') {
  errors.push('G3: execution_metadata.tokens_consumed.input deve ser número');
}

// findings — evidence_excerpt para severity >= medium
const mediumPlusSeverities = new Set(['medium', 'high', 'critical']);
const findingsNeedingEvidence = (output.findings || []).filter(f => mediumPlusSeverities.has(f.severity));
const findingsWithMissingEvidence = findingsNeedingEvidence.filter(f => !f.evidence_excerpt || f.evidence_excerpt.trim() === '');

// Para GP em pipeline n8n, evidence_excerpt pode ser null em findings gerados de texto livre
// Registra mas não falha a validação
validationReport.evidence_excerpts_present = findingsWithMissingEvidence.length === 0;

// ocg_contributions
const ocgIndividual = output.ocg_contributions?.individual;
const ocgGlobalDelta = output.ocg_contributions?.global_delta;

if (ocgIndividual && Object.keys(ocgIndividual).length > 0) {
  validationReport.ocg_individual_non_empty = true;
} else {
  errors.push('G3: ocg_contributions.individual não pode ser vazio');
}

if (ocgGlobalDelta && Object.keys(ocgGlobalDelta).length > 0) {
  validationReport.ocg_global_delta_non_empty = true;
} else {
  errors.push('G3: ocg_contributions.global_delta não pode ser vazio');
}

// Emite output independentemente de erros (G3 não bloqueia — status=failed destrava Consolidador)
const hasErrors = errors.length > 0;
const finalOutput = {
  ...output,
  status: hasErrors ? 'partial' : 'completed',
  validation_self_report: validationReport,
  g3_errors: hasErrors ? errors : []
};

// Se erros críticos, marcar como failed mas ainda enviar ao Consolidador
if (!validationReport.schema_version_check || !validationReport.score_in_range) {
  finalOutput.status = 'failed';
}

return [{
  json: {
    persona_output: finalOutput,
    provider_chain: item.provider_chain,
    callback_url: item.callback_url,
    ingestion_id: item.ingestion_id,
    project_id: item.project_id,
    g3_has_errors: hasErrors,
    g3_errors: errors
  }
}];

// Handler de erro global do GP Orquestrador
// Captura falha e envia PersonaOutput com status=failed ao Consolidador
// Isso destranca o Consolidador (que conta expected_count vs received_count)

const crypto = require('crypto');

const errorData = $input.first();
const errorMessage = errorData.json.error?.message || errorData.json.message || 'Erro desconhecido no GP Orquestrador';

let ingestion_id = 'unknown';
let project_id = 'unknown';
let provider_chain = [];
let callback_url = `${$env.GCA_CALLBACK_BASE_URL}/api/webhooks/ingestion-complete`;

try {
  const webhookBody = $('Webhook Trigger').first().json.body;
  ingestion_id = webhookBody?.ingestion_id || 'unknown';
  project_id = webhookBody?.project_id || 'unknown';
  provider_chain = webhookBody?.provider_chain || [];
  callback_url = webhookBody?.callback_url || callback_url;
} catch (_) {
  // Sem contexto do webhook disponível
}

// Monta PersonaOutput de falha para não travar o Consolidador
const failedOutput = {
  schema_version: 'PersonaOutput-v2',
  ingestion_id,
  persona_tag: 'GP',
  persona_name: 'Gerente de Projetos',
  execution_metadata: {
    started_at: new Date().toISOString(),
    completed_at: new Date().toISOString(),
    model_used: provider_chain[0]?.model || 'unknown',
    tokens_consumed: { input: 0, output: 0 },
    chunk_index: 0,
    total_chunks: 1,
    extraction_source_format: 'txt'
  },
  score: 0,
  score_rationale: `Falha de execução: ${errorMessage.substring(0, 240)}`,
  blocking: false,
  blocking_reason: null,
  status: 'failed',
  findings: [{
    id: 'gp-execution-error',
    severity: 'critical',
    category: 'execution_error',
    title: 'Falha na execução do GP Orquestrador',
    description: errorMessage,
    location_hint: null,
    evidence_excerpt: null
  }],
  recommendations: [],
  ocg_contributions: {
    individual: { error: errorMessage },
    global_delta: {}
  },
  validation_self_report: {
    schema_version_check: true,
    score_in_range: true,
    evidence_excerpts_present: false,
    ocg_individual_non_empty: true,
    ocg_global_delta_non_empty: false
  }
};

return [{
  json: {
    persona_output: failedOutput,
    ingestion_id,
    project_id,
    provider_chain,
    callback_url,
    is_error_fallback: true
  }
}];
